import { useAuth } from '../hooks/useAuth';
import { SignInForm } from '../components/Auth/SignInForm';

export function Home() {
  const { user } = useAuth();

  return (
    <div className="text-center">
      <h1 className="text-4xl font-bold mb-6">Welcome to VSA</h1>
      {user ? (
        <div>
          <p className="text-xl mb-4">Hello, {user.email}!</p>
          <p className="text-gray-600">You are signed in and ready to participate in events.</p>
        </div>
      ) : (
        <div>
          <p className="text-xl mb-8">Please sign in to access events and track your points.</p>
          <SignInForm />
        </div>
      )}
    </div>
  );
}
